+/// Derive table name from struct name: convert to snake_case and pluralize.
+///
+/// Examples:
+/// - `Hero` -> `heroes`
+/// - `TeamMember` -> `team_members`
+/// - `Person` -> `people`
+/// - `Category` -> `categories`
+fn derive_table_name(struct_name: &str) -> String {
+    let snake = to_snake_case(struct_name);
+    pluralize(&snake)
+}
+
+/// Convert PascalCase to snake_case.
+///
+/// Examples:
+/// - `Hero` -> `hero`
+/// - `TeamMember` -> `team_member`
+/// - `HTTPServer` -> `http_server`
+fn to_snake_case(s: &str) -> String {
+    let mut result = String::with_capacity(s.len() + 4);
+    let mut chars = s.chars().peekable();
+
+    while let Some(c) = chars.next() {
+        if c.is_uppercase() {
+            // Don't add underscore at the start or after another uppercase
+            // (for sequences like "HTTP")
+            if !result.is_empty() {
+                // Check if this is the start of a new word
+                // (uppercase followed by lowercase OR end of acronym)
+                let next_is_lower = chars.peek().is_some_and(|n| n.is_lowercase());
+                let prev_is_lower = result.chars().last().is_some_and(|p| p.is_lowercase());
+
+                if prev_is_lower || next_is_lower {
+                    result.push('_');
+                }
+            }
+            result.push(c.to_ascii_lowercase());
+        } else {
+            result.push(c);
+        }
+    }
+
+    result
+}
