+/// Intermediate struct for collecting field attributes.
+#[derive(Default)]
+struct FieldAttrs {
+    column: Option<String>,
+    sql_type: Option<String>,
+    nullable: Option<bool>,
+    primary_key: bool,
+    auto_increment: bool,
+    unique: bool,
+    foreign_key: Option<String>,
+    default: Option<String>,
+    index: Option<String>,
+    skip: bool,
+    skip_insert: bool,
+    skip_update: bool,
